mapper.select:
SELECT id, user_id, password_hash, is_locked
FROM account_passwords
WHERE user_id = #{userId}

mapper.insert:
INSERT INTO account_passwords (user_id, password_hash)
VALUES (#{userId}, #{passwordHash})
ON DUPLICATE KEY UPDATE password_hash = #{passwordHash}

mapper.update:
UPDATE account_passwords
SET is_locked = #{isLocked}
WHERE user_id = #{userId}
